def test_infer_shapes_with_fallback_skips_external_data_models(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    external_model = _make_external_data_add_model(unknown_rank=True)
    infer_shapes_called = False

    def _unexpected_infer_shapes(model: onnx.ModelProto) -> onnx.ModelProto:
        nonlocal infer_shapes_called
        infer_shapes_called = True
        raise AssertionError("infer_shapes must not run for external_data models")

    fake_symbolic_module = types.ModuleType("onnxruntime.tools.symbolic_shape_infer")

    class _UnexpectedSymbolicShapeInference:
        @staticmethod
        def infer_shapes(*args: Any, **kwargs: Any) -> onnx.ModelProto:
            raise AssertionError("symbolic shape inference must not run for external_data models")

    fake_symbolic_module.SymbolicShapeInference = _UnexpectedSymbolicShapeInference
    monkeypatch.setattr(onnx.shape_inference, "infer_shapes", _unexpected_infer_shapes)
    monkeypatch.setitem(
        sys.modules,
        "onnxruntime.tools.symbolic_shape_infer",
        fake_symbolic_module,
    )

    inferred_model = _infer_shapes_with_fallback(external_model)

    assert inferred_model is external_model
    assert infer_shapes_called is False


def test_infer_shapes_with_fallback_still_runs_for_non_external_models(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    infer_shapes_called = False

    def _record_infer_shapes(model: onnx.ModelProto) -> onnx.ModelProto:
        nonlocal infer_shapes_called
        infer_shapes_called = True
        return model

    monkeypatch.setattr(onnx.shape_inference, "infer_shapes", _record_infer_shapes)

    inferred_model = _infer_shapes_with_fallback(_make_add_model())

    assert infer_shapes_called is True
    assert isinstance(inferred_model, onnx.ModelProto)


def test_run_onnx_and_collect_outputs_skips_infer_shapes_for_external_data(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    external_model = _make_external_data_add_model()
    infer_shapes_called = False

    def _unexpected_infer_shapes(model: onnx.ModelProto) -> onnx.ModelProto:
        nonlocal infer_shapes_called
        infer_shapes_called = True
        return model

    class _FakeSession:
        def __init__(self, *args: Any, **kwargs: Any) -> None:
            pass

        def run(
            self,
            output_names: list[str],
            sample_inputs: dict[str, np.ndarray],
        ) -> list[np.ndarray]:
            x = np.asarray(sample_inputs["x"], dtype=np.float32)
            return [x + np.asarray([[1.0, 2.0, 3.0]], dtype=np.float32) for _ in output_names]

    monkeypatch.setattr(onnx.shape_inference, "infer_shapes", _unexpected_infer_shapes)
    monkeypatch.setattr(ort, "InferenceSession", _FakeSession)

    outputs = _run_onnx_and_collect_outputs(
        onnx_model=external_model,
        sample_inputs={"x": np.asarray([[10.0, 20.0, 30.0]], dtype=np.float32)},
        output_names=["y"],
    )

    assert infer_shapes_called is False
    assert np.array_equal(
        outputs["y"],
        np.asarray([[11.0, 22.0, 33.0]], dtype=np.float32),
    )


def test_flatbuffer_direct_topological_sort_reorders_producer_before_consumer() -> None:
    model_ir = ModelIR(name="topological_sort_test")
    model_ir.inputs = ["x"]
    model_ir.outputs = ["y"]
    model_ir.tensors["x"] = TensorIR(
        name="x",
        dtype="FLOAT32",
        shape=[1, 1, 2, 3],
        shape_signature=[1, 1, 2, 3],
    )
    model_ir.tensors["perm"] = TensorIR(
        name="perm",
        dtype="INT32",
        shape=[4],
        shape_signature=[4],
        data=np.asarray([0, 2, 3, 1], dtype=np.int32),
        is_variable=False,
    )
    model_ir.tensors["x_nhwc"] = TensorIR(
        name="x_nhwc",
        dtype="FLOAT32",
        shape=[1, 2, 3, 1],
        shape_signature=[1, 2, 3, 1],
    )
    model_ir.tensors["bias"] = TensorIR(
        name="bias",
        dtype="FLOAT32",
        shape=[1, 2, 3, 1],
        shape_signature=[1, 2, 3, 1],
        data=np.zeros((1, 2, 3, 1), dtype=np.float32),
        is_variable=False,
    )
    model_ir.tensors["y"] = TensorIR(
        name="y",
        dtype="FLOAT32",
        shape=[1, 2, 3, 1],
        shape_signature=[1, 2, 3, 1],
    )
    model_ir.operators = [
        OperatorIR(
            op_type="ADD",
            inputs=["x_nhwc", "bias"],
            outputs=["y"],
            options={},
        ),
        OperatorIR(
            op_type="TRANSPOSE",
            inputs=["x", "perm"],
            outputs=["x_nhwc"],
            options={},
        ),
    ]

    stats = _topologically_sort_operators(model_ir)
    assert stats["cycle_detected"] == 0
    assert stats["reordered_operators"] > 0
    assert [str(op.op_type) for op in model_ir.operators] == ["TRANSPOSE", "ADD"]


def test_flatbuffer_direct_transpose_layernorm_stats_nhwc_propagation() -> None:
    model_ir = ModelIR(name="transpose_layernorm_stats_nhwc_propagation_test")
    model_ir.inputs = ["x_nhwc"]
    model_ir.outputs = ["y"]

    model_ir.tensors["x_nhwc"] = TensorIR(
        name="x_nhwc",
        dtype="FLOAT32",
        shape=[1, 1, 5, 3],
        shape_signature=[1, 1, 5, 3],
    )
    model_ir.tensors["perm_nhwc_to_nchw"] = TensorIR(
        name="perm_nhwc_to_nchw",
        dtype="INT32",
        shape=[4],
        shape_signature=[4],
        data=np.asarray([0, 3, 1, 2], dtype=np.int32),
        is_variable=False,
    )
    model_ir.tensors["x_nchw"] = TensorIR(
        name="x_nchw",
        dtype="FLOAT32",
        shape=[1, 3, 1, 5],
        shape_signature=[1, 3, 1, 5],
    )
    model_ir.tensors["mean_axes"] = TensorIR(
        name="mean_axes",
        dtype="INT32",
        shape=[1],
        shape_signature=[1],
        data=np.asarray([1], dtype=np.int32),
        is_variable=False,
    )
    model_ir.tensors["var_axes"] = TensorIR(
        name="var_axes",
        dtype="INT32",
        shape=[1],
        shape_signature=[1],
        data=np.asarray([1], dtype=np.int32),
        is_variable=False,
    )
    model_ir.tensors["m"] = TensorIR(
        name="m",
        dtype="FLOAT32",
        shape=[1, 1, 1, 5],
        shape_signature=[1, 1, 1, 5],
    )
    model_ir.tensors["n"] = TensorIR(
        name="n",
        dtype="FLOAT32",
        shape=[1, 1, 1, 5],
        shape_signature=[1, 1, 1, 5],
    )
    model_ir.tensors["d"] = TensorIR(
        name="d",
        dtype="FLOAT32",
        shape=[1, 3, 1, 5],
        shape_signature=[1, 3, 1, 5],
    )
    model_ir.tensors["sq"] = TensorIR(
        name="sq",
        dtype="FLOAT32",
        shape=[1, 3, 1, 5],
        shape_signature=[1, 3, 1, 5],
    )
    model_ir.tensors["v"] = TensorIR(
        name="v",
        dtype="FLOAT32",
        shape=[1, 1, 1, 5],
        shape_signature=[1, 1, 1, 5],
    )
    model_ir.tensors["eps"] = TensorIR(
        name="eps",
        dtype="FLOAT32",
        shape=[],
        shape_signature=[],
        data=np.asarray(1e-6, dtype=np.float32),
        is_variable=False,
    )
    model_ir.tensors["y"] = TensorIR(
        name="y",
        dtype="FLOAT32",
        shape=[1, 1, 1, 5],
        shape_signature=[1, 1, 1, 5],
    )
    model_ir.tensors["keep_nchw_bias"] = TensorIR(
        name="keep_nchw_bias",
        dtype="FLOAT32",
        shape=[1, 3, 1, 5],
        shape_signature=[1, 3, 1, 5],
        data=np.zeros((1, 3, 1, 5), dtype=np.float32),
        is_variable=False,
    )
    model_ir.tensors["keep_nchw"] = TensorIR(
        name="keep_nchw",
        dtype="FLOAT32",
        shape=[1, 3, 1, 5],
        shape_signature=[1, 3, 1, 5],
    )

    model_ir.operators = [
        OperatorIR(op_type="TRANSPOSE", inputs=["x_nhwc", "perm_nhwc_to_nchw"], outputs=["x_nchw"]),
        OperatorIR(
            op_type="MEAN",
            inputs=["x_nchw", "mean_axes"],
            outputs=["m"],
            options={"keepDims": True},
        ),
        OperatorIR(op_type="NEG", inputs=["m"], outputs=["n"]),
        OperatorIR(op_type="SUB", inputs=["x_nchw", "m"], outputs=["d"]),
        OperatorIR(op_type="MUL", inputs=["d", "d"], outputs=["sq"]),
        OperatorIR(
            op_type="MEAN",
            inputs=["sq", "var_axes"],
            outputs=["v"],
            options={"keepDims": True},
        ),
        OperatorIR(op_type="ADD", inputs=["v", "eps"], outputs=["y"]),
        # Keep one extra NCHW consumer so transpose must remain.
        OperatorIR(op_type="ADD", inputs=["x_nchw", "keep_nchw_bias"], outputs=["keep_nchw"]),
    ]

    stats = _optimize_transpose_layernorm_stats_nhwc_propagation_chains(model_ir)
    assert stats["optimized_transpose_layernorm_stats_nhwc_propagation_chains"] == 1

    mean0 = model_ir.operators[1]
    sub = model_ir.operators[3]
    mean1 = model_ir.operators[5]
    assert list(mean0.inputs) == ["x_nhwc", "mean_axes"]
    assert list(sub.inputs) == ["x_nhwc", "m"]
    assert list(mean1.inputs) == ["sq", "var_axes"]
    assert np.array_equal(np.asarray(model_ir.tensors["mean_axes"].data), np.asarray([3], dtype=np.int32))
    assert np.array_equal(np.asarray(model_ir.tensors["var_axes"].data), np.asarray([3], dtype=np.int32))

    # The transpose remains because it still feeds keep_nchw.
    assert [str(op.op_type) for op in model_ir.operators].count("TRANSPOSE") == 1
    assert list(model_ir.tensors["m"].shape) == [1, 1, 5, 1]
    assert list(model_ir.tensors["d"].shape) == [1, 1, 5, 3]
    assert list(model_ir.tensors["sq"].shape) == [1, 1, 5, 3]
    assert list(model_ir.tensors["v"].shape) == [1, 1, 5, 1]


