    assert list(model_ir.tensors["mul_out"].shape) == [1, 3, 2, 4]

    add_ops = [op for op in model_ir.operators if str(op.op_type) == "ADD"]
    assert len(add_ops) == 1
    assert "mul_out" in [str(v) for v in list(add_ops[0].inputs)]


