    model_ir.tensors["q2"] = TensorIR(name="q2", dtype="INT8", shape=[1, 3, 2, 2], shape_signature=[1, 3, 2, 2])
    model_ir.tensors["q3"] = TensorIR(name="q3", dtype="INT8", shape=[1, 3, 2, 2], shape_signature=[1, 3, 2, 2])
