    assert [str(v) for v in list(reshape_op.inputs)] == ["y_nhwc", "reshape_shape"]

    assert list(model_ir.tensors["sig_nchw"].shape) == [1, 1, 1, 8]
    assert list(model_ir.tensors["mul_nchw"].shape) == [1, 6, 6, 8]


