    _add_tensor("mean_nhwc", [1, 1, 1, 8])
    _add_tensor("gate_pre_in_nhwc", [1, 1, 1, 8])
    _add_tensor("gate_nchw", [1, 8, 1, 1])
    _add_tensor("sig2_nchw", [1, 8, 1, 1])
