    add_op = next(op for op in model_ir.operators if str(op.op_type) == "ADD")
    assert list(mul_op.inputs) == ["x_nhwc0", "x_nhwc0"]
    assert list(add_op.inputs) == ["x_nhwc0", "x_nhwc0"]


