    lhs_sq = next(op for op in model_ir.operators if str(op.op_type) == "SQUEEZE" and str(op.outputs[0]) == "lhs3")
    rhs_sq = next(op for op in model_ir.operators if str(op.op_type) == "SQUEEZE" and str(op.outputs[0]) == "rhs3")
