    n, w, c = 1, 5, 4
    c2 = int(c * 2)
    k = int(c2 * w)

    # Left branch already in [N,W,C], but consumed via legacy rank-3 transpose [N,C,W].
    model_ir.tensors["lhs_nwc"] = TensorIR(name="lhs_nwc", dtype="FLOAT32", shape=[n, w, c], shape_signature=[n, w, c])
