        OperatorIR(op_type="GELU", inputs=["x_nchw"], outputs=["u_nchw"], options={"approximate": False}),
        OperatorIR(op_type="TRANSPOSE", inputs=["u_nchw", "perm_mid"], outputs=["u_nhcw"], options={}),
